  FunctionType replacementFnType = fnType.visit(replacer)
      .toMaybeFunctionType();
  Preconditions.checkNotNull(replacementFnType);

  // Check if the inferred function type matches the expected type
  JSType expectedType = callTarget.getJSType();
  if (expectedType != null && !expectedType.isEquivalentTo(replacementFnType)) {
